mapper.select:
/* 카테고리 목록 조회 library.selectCategoryList */ SELECT CATEGORY_ID , USER_ID , CATEGORY_NM , COLOR , SORT_ORD , CREATE_DT FROM TB_KNOW_CAT WHERE 1=1
AND USER_ID = #{userId}
ORDER BY SORT_ORD, CREATE_DT DESC

/* 카드 목록 조회 library.selectCardList */ SELECT CARD_ID , USER_ID , CATEGORY_ID , LOG_ID , SVC_TY , TITLE , TAGS , PIN_YN , ARCHIVE_YN , SORT_ORD , SRC_DOCS , SQL_CODE , CHART_CFG , QRY_RSLT , USE_YN , CREATE_DT , MODIFY_DT FROM TB_KNOW_CARD WHERE 1=1
AND USER_ID = #{userId}
AND CATEGORY_ID = #{categoryId}
AND USE_YN = #{useYn}
AND ARCHIVE_YN = #{archiveYn}
ORDER BY SORT_ORD, CREATE_DT DESC

mapper.update:
/* 카드 PIN 여부 업데이트 library.updateCardPin */
UPDATE TB_KNOW_CARD
SET PIN_YN = #{pinYn}
    , MODIFY_DT = NOW()
WHERE CARD_ID = #{cardId}

mapper.insert:
/* 카테고리 등록/수정 library.insertCategory */

    SELECT CASE WHEN #{sortOrd, jdbcType=INTEGER} IS NULL OR #{sortOrd, jdbcType=INTEGER} = 0
        THEN (SELECT IFNULL(MAX(SORT_ORD), 0) + 1 FROM TB_KNOW_CAT WHERE USER_ID = #{userId} AND SORT_ORD > 0)
        ELSE #{sortOrd, jdbcType=INTEGER}
    END

INSERT INTO TB_KNOW_CAT (
    CATEGORY_ID
    , USER_ID
    , CATEGORY_NM
    , COLOR
    , SORT_ORD
    , CREATE_DT
) VALUES (
    #{categoryId}
    , #{userId}
    , #{categoryNm}
    , #{color}
    , #{sortOrd, jdbcType=INTEGER}
    , NOW()
)
ON DUPLICATE KEY UPDATE
    CATEGORY_NM = VALUES(CATEGORY_NM)
    , COLOR = VALUES(COLOR)
    , SORT_ORD = VALUES(SORT_ORD)
